// makeLoader builds a DocumentLoader from a config map with an optional enrich override.
// enrichOverride nil means use config value; non-nil overrides it.
func makeLoader(cfg map[string]interface{}, enrichOverride *bool) (*DocumentLoader, error) {
	lcRaw, _ := cfg["loader"]
	lc, _ := lcRaw.(map[string]interface{})
	if lc == nil {
		lc = map[string]interface{}{}
	}
	extraRaw, _ := lc["extra_extractors"].([]interface{})
	var extractors []Extractor
	for _, e := range extraRaw {
		name, _ := e.(string)
		ext, err := makeExtractor(name)
		if err != nil {
			return nil, err
		}
		extractors = append(extractors, ext)
	}
	enrich := true
	if enrichOverride != nil {
		enrich = *enrichOverride
	} else if v, ok := lc["enrich_context"].(bool); ok {
		enrich = v
	}
	minChunk := intFromMap(lc, "min_chunk_size", 1100)
	maxChunk := intFromMap(lc, "max_chunk_size", 2200)
	var extraPtr []Extractor
	if len(extractors) > 0 {
		extraPtr = extractors
	}
	return NewDocumentLoader(minChunk, maxChunk, enrich, extraPtr), nil
}

