// ingestGlob globs a directory and loads each non-dot file into chunks.
func ingestGlob(loader *DocumentLoader, src map[string]interface{}) ([]DocumentChunk, error) {
	basePath, _ := src["path"].(string)
	pattern, _ := src["pattern"].(string)
	if pattern == "" {
		pattern = "*"
	}
	prefix, _ := src["name_prefix"].(string)
	docType, _ := src["doc_type"].(string)
	matches, err := filepath.Glob(filepath.Join(basePath, pattern))
	if err != nil {
		return nil, fmt.Errorf("glob %s/%s: %w", basePath, pattern, err)
	}
	sort.Strings(matches)
	var chunks []DocumentChunk
	for _, p := range matches {
		base := filepath.Base(p)
		if strings.HasPrefix(base, ".") {
			continue
		}
		stem := strings.TrimSuffix(base, filepath.Ext(base))
		name := prefix + stem
		if docType != "" {
			data, err := os.ReadFile(p)
			if err != nil {
				return nil, fmt.Errorf("read %s: %w", p, err)
			}
			loaded, err := loader.LoadBytes(data, name, docType)
			if err != nil {
				return nil, err
			}
			chunks = append(chunks, loaded...)
		} else {
			loaded, err := loader.Load(p, name)
			if err != nil {
				return nil, err
			}
			chunks = append(chunks, loaded...)
		}
	}
	return chunks, nil
}

// ingestJSONArray reads a JSON file, iterates the named array field, and loads each item.
func ingestJSONArray(loader *DocumentLoader, src map[string]interface{}) ([]DocumentChunk, error) {
	filePath, _ := src["path"].(string)
	arrayField, _ := src["array_field"].(string)
	var idPath []string
	if raw, ok := src["id_path"].(string); ok && raw != "" {
		for _, part := range strings.Split(raw, ".") {
			idPath = append(idPath, part)
		}
	}
	data, err := os.ReadFile(filePath)
	if err != nil {
		return nil, fmt.Errorf("read %s: %w", filePath, err)
	}
	var obj interface{}
	if err := json.Unmarshal(data, &obj); err != nil {
		return nil, fmt.Errorf("json parse: %w", err)
	}
	var items []interface{}
	if m, ok := obj.(map[string]interface{}); ok {
		if arr, ok := m[arrayField].([]interface{}); ok {
			items = arr
		}
	} else if arr, ok := obj.([]interface{}); ok {
		items = arr
	}
	stem := strings.TrimSuffix(filepath.Base(filePath), filepath.Ext(filePath))
	var chunks []DocumentChunk
	for _, item := range items {
		var nameVal interface{} = item
		for _, key := range idPath {
			if m, ok := nameVal.(map[string]interface{}); ok {
				nameVal = m[key]
			} else {
				nameVal = "unknown"
			}
		}
		name := ""
		if nameVal != nil {
			name = fmt.Sprintf("%v", nameVal)
		}
		if name == "" {
			name = stem
		}
		payload, err := json.Marshal(map[string]interface{}{arrayField: []interface{}{item}})
		if err != nil {
			return nil, err
		}
		loaded, err := loader.LoadBytes(payload, name, "json")
		if err != nil {
			return nil, err
		}
		chunks = append(chunks, loaded...)
	}
	return chunks, nil
}

// ingestSQL runs a SQL query and loads each row as a text chunk, or delegates to LoadFromDB.
func ingestSQL(loader *DocumentLoader, src map[string]interface{}) ([]DocumentChunk, error) {
	connection, _ := src["connection"].(string)
	query := strings.TrimSpace(src["query"].(string))
	name := "sql_source"
	if n, ok := src["name"].(string); ok && n != "" {
		name = n
	}
	nameCol, _ := src["name_col"].(string)
	contentCol, _ := src["content_col"].(string)
	if nameCol != "" && contentCol != "" {
		dbPath := strings.TrimPrefix(connection, "duckdb:///")
		db, err := duckdbOpen(dbPath)
		if err != nil {
			return nil, fmt.Errorf("duckdb open: %w", err)
		}
		defer db.Close()
		colNames, rows, err := duckdbQueryAll(db, query)
		if err != nil {
			return nil, fmt.Errorf("query: %w", err)
		}
		nameIdx := -1
		contentIdx := -1
		for i, col := range colNames {
			if col == nameCol {
				nameIdx = i
			}
			if col == contentCol {
				contentIdx = i
			}
		}
		if nameIdx < 0 || contentIdx < 0 {
			return nil, fmt.Errorf("column not found: name_col=%s content_col=%s", nameCol, contentCol)
		}
		var chunks []DocumentChunk
		for _, row := range rows {
			rowName := fmt.Sprintf("%v", row[nameIdx])
			rowContent := fmt.Sprintf("%v", row[contentIdx])
			loaded, err := loader.LoadBytes([]byte(rowContent), rowName, "text")
			if err != nil {
				return nil, err
			}
			chunks = append(chunks, loaded...)
		}
		return chunks, nil
	}
	return loader.LoadFromDB(connection, map[string]string{name: query})
}

// embedChunks encodes chunk contents in batches and returns a flat slice of float32 vectors.
func embedChunks(chunks []DocumentChunk, cfg map[string]interface{}) ([][]float32, error) {
	ecRaw, _ := cfg["embed"]
	ec, _ := ecRaw.(map[string]interface{})
	if ec == nil {
		ec = map[string]interface{}{}
	}
	modelName := "BAAI/bge-large-en-v1.5"
	if m, ok := ec["model"].(string); ok && m != "" {
		modelName = m
	}
	batchSize := 256
	if b, ok := ec["batch_size"].(int); ok && b > 0 {
		batchSize = b
	}
	texts := make([]string, len(chunks))
	for i, c := range chunks {
		texts[i] = c.Content
	}
	model, err := LoadSentenceTransformer(modelName)
	if err != nil {
		return nil, fmt.Errorf("load model %s: %w", modelName, err)
	}
	var vecs [][]float32
	for i := 0; i < len(texts); i += batchSize {
		end := i + batchSize
		if end > len(texts) {
			end = len(texts)
		}
		batch := texts[i:end]
		v, err := model.Encode(batch, false, true)
		if err != nil {
			return nil, fmt.Errorf("encode batch at %d: %w", i, err)
		}
		vecs = append(vecs, v...)
		done := end
		if (i/batchSize)%10 == 0 {
			fmt.Printf("  embedded %d/%d\n", done, len(texts))
		}
	}
	return vecs, nil
}

