// resolveDomains translates namespace + domain name filters into domain ID slices.
// Returns nil when both inputs are nil (no filter).
func (idx *Index) resolveDomains(namespaces, domains []string) []string {
	if namespaces == nil && domains == nil {
		return nil
	}
	targetNS := namespaces
	if len(targetNS) == 0 {
		for ns := range idx.domainMap {
			targetNS = append(targetNS, ns)
		}
	}
	var ids []string
	if domains != nil {
		for _, ns := range targetNS {
			nsMap, ok := idx.domainMap[ns]
			if !ok {
				nsMap = map[string]string{}
			}
			for _, name := range domains {
				if did, found := nsMap[name]; found {
					ids = append(ids, did)
				}
			}
		}
	} else {
		for _, ns := range targetNS {
			nsMap, ok := idx.domainMap[ns]
			if !ok {
				continue
			}
			for _, did := range nsMap {
				ids = append(ids, did)
			}
		}
	}
	if len(ids) == 0 {
		return nil
	}
	return ids
}
